+import type { AddressInfo } from "node:net";
+import net from "node:net";
+import { afterEach, describe, expect, it } from "vitest";
+import { WebSocketServer, type RawData, type WebSocket } from "ws";
+import { GatewayClientTransport, OpenClaw } from "./index.js";
+
+type JsonObject = Record<string, unknown>;
+
+const servers: WebSocketServer[] = [];
+
+function sendJson(socket: WebSocket, payload: JsonObject): void {
+  socket.send(JSON.stringify(payload));
+}
+
+function readRawMessage(raw: RawData): string {
+  if (typeof raw === "string") {
+    return raw;
+  }
+  if (Buffer.isBuffer(raw)) {
+    return raw.toString("utf8");
+  }
+  if (raw instanceof ArrayBuffer) {
+    return Buffer.from(raw).toString("utf8");
+  }
+  return Buffer.concat(raw).toString("utf8");
+}
+
+async function reservePort(): Promise<number> {
+  const server = net.createServer();
+  await new Promise<void>((resolve) => server.listen(0, "127.0.0.1", resolve));
+  const { port } = server.address() as AddressInfo;
+  await new Promise<void>((resolve, reject) => {
+    server.close((error) => (error ? reject(error) : resolve()));
+  });
+  return port;
+}
+
+async function createFakeGateway(port = 0): Promise<{ url: string; close: () => Promise<void> }> {
+  const server = new WebSocketServer({ host: "127.0.0.1", port });
+  servers.push(server);
+  await new Promise<void>((resolve) => server.once("listening", resolve));
+  let seq = 1;
+
+  server.on("connection", (socket) => {
+    sendJson(socket, {
+      type: "event",
+      event: "connect.challenge",
+      seq: seq++,
+      payload: { nonce: "sdk-e2e-nonce" },
+    });
+
+    socket.on("message", (raw) => {
+      const frame = JSON.parse(readRawMessage(raw)) as {
+        id: string;
+        method: string;
+        params?: unknown;
+      };
+
+      if (frame.method === "connect") {
+        sendJson(socket, {
+          type: "res",
+          id: frame.id,
+          ok: true,
+          payload: {
+            type: "hello-ok",
+            protocol: 1,
+            server: { version: "sdk-e2e", connId: "conn-sdk-e2e" },
+            features: {
+              methods: [
+                "agent",
+                "agent.wait",
+                "connect",
+                "sessions.abort",
+                "sessions.create",
+                "sessions.send",
+              ],
+              events: ["agent", "sessions.changed"],
+            },
+            snapshot: {
+              presence: [],
+              health: {},
+              stateVersion: { presence: 0, health: 0 },
+              uptimeMs: 1,
+            },
+            auth: { role: "operator", scopes: [] },
+            policy: {
+              maxPayload: 262144,
+              maxBufferedBytes: 262144,
+              tickIntervalMs: 30000,
+            },
+          },
+        });
+        return;
+      }
+
+      if (frame.method === "agent") {
+        const params = frame.params as { sessionKey?: string } | undefined;
+        sendJson(socket, {
+          type: "res",
+          id: frame.id,
+          ok: true,
+          payload: { status: "accepted", runId: "run-sdk-e2e", sessionKey: params?.sessionKey },
+        });
+        setTimeout(() => {
+          sendJson(socket, {
+            type: "event",
+            event: "agent",
+            seq: seq++,
+            payload: {
+              runId: "run-sdk-e2e",
+              sessionKey: params?.sessionKey,
+              stream: "lifecycle",
+              ts: Date.now(),
+              data: { phase: "start" },
+            },
+          });
+          sendJson(socket, {
+            type: "event",
+            event: "agent",
+            seq: seq++,
+            payload: {
+              runId: "run-sdk-e2e",
+              sessionKey: params?.sessionKey,
+              stream: "assistant",
+              ts: Date.now(),
